import { Component } from 'react';

class ErrorBoundary extends Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false };
    }

    static getDerivedStateFromError(error) {
        return { hasError: true };
    }

    componentDidCatch(error, errorInfo) {
        console.warn("ErrorBoundary gracefully caught a 3D Canvas error:", error, errorInfo);
    }

    render() {
        if (this.state.hasError) {
            return (
                <div className="w-full h-full min-h-[500px] flex items-center justify-center bg-slate-100 dark:bg-slate-800/50 rounded-[3rem] border border-slate-200 dark:border-slate-700/50">
                    <div className="text-center p-8 max-w-sm">
                        <div className="w-16 h-16 mx-auto mb-4 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full flex items-center justify-center">
                            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z" /><path d="M12 9v4" /><path d="M12 17h.01" /></svg>
                        </div>
                        <h2 className="text-xl font-black text-slate-900 dark:text-white mb-2">3D Experience Unavailable</h2>
                        <p className="text-sm font-medium text-slate-500 dark:text-slate-400 mb-6">Your device graphics or network prevented the WebGL Canvas from loading.</p>
                        <button
                            onClick={() => window.location.reload()}
                            className="px-6 py-3 bg-slate-900 dark:bg-primary-600 hover:bg-slate-800 dark:hover:bg-primary-700 text-white font-bold rounded-xl transition-colors shadow-lg"
                        >
                            Reload Page
                        </button>
                    </div>
                </div>
            );
        }

        return this.props.children;
    }
}

export default ErrorBoundary;

import { useEffect, useState, useRef } from 'react';
import { useFrame, Canvas } from '@react-three/fiber';
import * as THREE from 'three';
import { MeshTransmissionMaterial, Environment, ContactShadows } from '@react-three/drei';
import { motion, AnimatePresence } from 'framer-motion';

const ProceduralShoppingBag = () => {
    const groupRef = useRef();

    // Additional floating fragments
    const frag1 = useRef();
    const frag2 = useRef();

    useFrame((state) => {
        if (!groupRef.current) return;
        // Gentle rotation and floating
        groupRef.current.rotation.y += 0.015;
        groupRef.current.position.y = Math.sin(state.clock.elapsedTime * 2) * 0.15;

        // Interactive mouse tracking (subtle)
        groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, (state.pointer.y * Math.PI) / 6, 0.05);
        groupRef.current.rotation.z = THREE.MathUtils.lerp(groupRef.current.rotation.z, -(state.pointer.x * Math.PI) / 8, 0.05);

        if (frag1.current) {
            frag1.current.rotation.x += 0.02;
            frag1.current.position.y = Math.sin(state.clock.elapsedTime * 3) * 0.3 + 0.5;
        }

        if (frag2.current) {
            frag2.current.rotation.z += 0.03;
            frag2.current.position.x = Math.cos(state.clock.elapsedTime * 2) * 0.5 - 0.5;
        }
    });

    return (
        <group ref={groupRef} scale={1.2}>
            {/* Bag Body (Sleek Glass/Acrylic look) */}
            <mesh position={[0, -0.2, 0]} castShadow>
                <boxGeometry args={[1.6, 2.2, 0.8]} />
                <MeshTransmissionMaterial
                    backside
                    thickness={0.5}
                    roughness={0.05}
                    transmission={1}
                    ior={1.4}
                    color="#2563eb"
                    chromaticAberration={0.1}
                />
            </mesh>

            {/* Inner contents to make it look like a real bag with an item */}
            <mesh position={[0, -0.5, 0]}>
                <boxGeometry args={[1.4, 1.4, 0.6]} />
                <meshStandardMaterial color="#ffffff" roughness={0.5} />
            </mesh>

            {/* Dynamic floating geometric fragments */}
            <group ref={frag1} position={[0, 0, 0]}>
                <mesh position={[1, 0.5, 0.5]}>
                    <octahedronGeometry args={[0.25, 0]} />
                    <MeshTransmissionMaterial thickness={0.5} roughness={0.1} transmission={1} ior={1.5} color="#38bdf8" chromaticAberration={0.1} />
                </mesh>
            </group>

            <group ref={frag2} position={[0, 0, 0]}>
                <mesh position={[-1, -0.5, 0.5]}>
                    <icosahedronGeometry args={[0.2]} />
                    <meshStandardMaterial color="#f43f5e" roughness={0.2} metalness={0.9} />
                </mesh>
            </group>

            <mesh position={[0, -0.2, 0]} rotation={[Math.PI / 2, 0, 0]}>
                <torusGeometry args={[1.5, 0.01, 16, 64]} />
                <meshStandardMaterial color="#4ade80" emissive="#4ade80" emissiveIntensity={0.8} />
            </mesh>
            <mesh position={[0, -0.2, 0]} rotation={[Math.PI / 2.5, 0.2, 0]}>
                <torusGeometry args={[1.2, 0.01, 16, 64]} />
                <meshStandardMaterial color="#38bdf8" emissive="#38bdf8" emissiveIntensity={0.5} />
            </mesh>

            <mesh position={[0, 0.6, 0.2]} rotation={[0.2, 0, 0]}>
                <planeGeometry args={[1.2, 1.2]} />
                <meshBasicMaterial color="#38bdf8" side={THREE.DoubleSide} transparent opacity={0.8} />
            </mesh>

            {/* Bag Handle Front */}
            <mesh position={[0, 1.1, 0.2]} rotation={[0, 0, 0]}>
                <torusGeometry args={[0.35, 0.06, 16, 32, Math.PI]} />
                <meshStandardMaterial color="#ffffff" roughness={0.3} metalness={0.5} />
            </mesh>

            {/* Bag Handle Back */}
            <mesh position={[0, 1.1, -0.2]} rotation={[0, 0, 0]}>
                <torusGeometry args={[0.35, 0.06, 16, 32, Math.PI]} />
                <meshStandardMaterial color="#ffffff" roughness={0.3} metalness={0.5} />
            </mesh>
        </group>
    );
};

const GlobalLoader = () => {
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const timer = setTimeout(() => {
            setIsLoading(false);
        }, 3500); // 3.5 seconds to interact with the glass loader
        return () => clearTimeout(timer);
    }, []);

    return (
        <AnimatePresence>
            {isLoading && (
                <motion.div
                    initial={{ opacity: 1 }}
                    exit={{ opacity: 0, scale: 1.05, filter: 'blur(20px)' }}
                    transition={{ duration: 1.2, ease: [0.16, 1, 0.3, 1] }} // Ultra smooth custom cubic-bezier
                    className="fixed inset-0 z-[9999] bg-[#020617] flex flex-col items-center justify-center overflow-hidden cursor-none"
                >
                    {/* Dark gradient backdrop */}
                    <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(49,46,129,0.15)_0%,rgba(2,6,23,1)_100%)]"></div>

                    {/* Interactive 3D Refracting Glass Canvas */}
                    <div className="absolute inset-0 w-full h-full">
                        <Canvas camera={{ position: [0, 0, 5], fov: 45 }} dpr={[1, 2]}>
                            <ambientLight intensity={0.5} />
                            <spotLight position={[10, 10, 10]} angle={0.2} penumbra={1} intensity={1.5} color="#ffffff" />
                            <ProceduralShoppingBag />
                            <Environment preset="city" />
                            <ContactShadows position={[0, -2, 0]} opacity={0.4} scale={10} blur={2.5} far={4} color="#000000" />
                        </Canvas>
                    </div>

                    {/* Premium Typography Overlay */}
                    <motion.div
                        initial={{ opacity: 0, y: 30 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 1.5, ease: "easeOut", delay: 0.5 }}
                        className="relative z-10 flex flex-col items-center justify-center h-full pointer-events-none"
                    >
                        <div className="mt-64 flex flex-col items-center">
                            <motion.h2
                                initial={{ letterSpacing: "0.5em" }}
                                animate={{ letterSpacing: "0.2em" }}
                                transition={{ duration: 2.5, ease: [0.16, 1, 0.3, 1] }}
                                className="text-4xl md:text-5xl font-black text-white uppercase tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-4"
                            >
                                Vertexia
                            </motion.h2>
                            <p className="text-blue-200/60 font-medium tracking-[0.3em] text-xs uppercase">Preparing Experience</p>
                        </div>
                    </motion.div>
                </motion.div>
            )}
        </AnimatePresence>
    );
};

export default GlobalLoader;

