// --- View Components ---

const GodViewGlobe = () => {
    const sphereRef = useRef();
    const sphereData = useMemo(() => {
        const points = new Float32Array(3000 * 3);
        for (let i = 0; i < 3000; i++) {
            const phi = Math.acos(-1 + (2 * i) / 3000);
            const theta = Math.sqrt(3000 * Math.PI) * phi;
            const r = 1.5 + (Math.random() * 0.05);
            points[i * 3] = r * Math.cos(theta) * Math.sin(phi);
            points[i * 3 + 1] = r * Math.sin(theta) * Math.sin(phi);
            points[i * 3 + 2] = r * Math.cos(phi);
        }
        return points;
    }, []);

    useFrame((state, delta) => {
        if (sphereRef.current) {
            sphereRef.current.rotation.y -= delta / 15;
            sphereRef.current.rotation.x -= delta / 25;
        }
    });

    return (
        <group rotation={[0, 0, Math.PI / 6]}>
            <Points ref={sphereRef} positions={sphereData} stride={3} frustumCulled={false}>
                <PointMaterial transparent color="#4ade80" size={0.02} sizeAttenuation={true} depthWrite={false} />
            </Points>
            <mesh>
