const Dashboard = ({ role }) => {
    const { user } = useSelector(state => state.auth);
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const currentRole = role || user?.role || 'buyer';
    const [activeTab, setActiveTab] = useState(currentRole === 'seller' ? 'products' : 'locker');

    const handleLogout = () => {
        import('../store/index').then(({ logout }) => {
            dispatch(logout());
            navigate('/login');
        });
    };

    const getMenuItems = () => {
        if (currentRole === 'admin') {
            return [
                { id: 'overview', label: 'Overview', icon: LayoutDashboard },
                { id: 'users', label: 'Users', icon: Users },
                { id: 'products', label: 'Products', icon: Package },
            ];
        } else if (currentRole === 'seller') {
            return [
                { id: 'overview', label: 'Dashboard', icon: LayoutDashboard },
                { id: 'products', label: 'Manage 3D Assets', icon: Package },
                { id: 'analytics', label: 'Analytics', icon: BarChart3 },
            ];
        } else {
            return [
                { id: 'overview', label: 'My Profile', icon: User },
                { id: 'locker', label: 'Locker Room', icon: Box },
                { id: 'orders', label: 'Order History', icon: Package },
            ];
        }
    };

    const renderContent = () => {
        // Handle common global tabs
        if (activeTab === 'settings') return <SettingsView />;

        // Admin
        if (currentRole === 'admin') {
            if (activeTab === 'overview') return <AdminView />;
            if (activeTab === 'users') return <AdminUsersView />;
            if (activeTab === 'products') return <AdminProductsView />;
        }

        // Seller
        if (currentRole === 'seller') {
            if (activeTab === 'overview') return <SellerAnalyticsView />;
            if (activeTab === 'analytics') return <SellerAnalyticsView />;
            if (activeTab === 'products') return <SellerProductsView />;
        }

        // Buyer
        if (currentRole === 'buyer') {
            if (activeTab === 'overview') return <BuyerProfileView />;
            if (activeTab === 'locker') return <LockerRoomView />;
            if (activeTab === 'orders') return <BuyerOrdersView />;
        }

        return (
            <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-sm p-12 text-center border border-slate-100 dark:border-slate-700 flex flex-col items-center justify-center min-h-[400px]">
                <Clock size={64} className="text-slate-300 dark:text-slate-600 mb-6" />
                <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2">Coming Soon</h2>
                <p className="text-slate-500 dark:text-slate-400 font-medium max-w-sm">This dashboard section is actively being built for Vertexia.</p>
            </div>
        );
    };

    return (
        <div className="bg-[#F8FAFC] dark:bg-[#020617] min-h-screen py-10 transition-colors duration-300">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex flex-col md:flex-row gap-8">
                    {/* Sidebar */}
                    <div className="w-full md:w-72 flex-shrink-0">
                        <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700 p-8 sticky top-24 transition-colors">
                            <div className="flex items-center space-x-4 mb-10">
                                <div className="w-14 h-14 rounded-full bg-gradient-to-r from-primary-600 to-indigo-600 flex items-center justify-center text-white font-black text-2xl uppercase shadow-lg shadow-primary-500/30 transition-colors">
                                    {user ? user.name.charAt(0) : (currentRole === 'admin' ? 'A' : (currentRole === 'seller' ? 'S' : 'J'))}
                                </div>
                                <div className="flex-1 overflow-hidden">
                                    <h3 className="font-black text-slate-900 dark:text-white text-lg truncate">
                                        {user ? user.name : (currentRole === 'admin' ? 'Admin Center' : (currentRole === 'seller' ? 'Seller Hub' : 'John Doe'))}
                                    </h3>
                                    <p className="text-xs font-bold text-primary-600 dark:text-primary-400 uppercase tracking-widest bg-primary-50 dark:bg-primary-900/30 inline-block px-2.5 py-1 rounded-lg mt-1 transition-colors">
                                        {currentRole}
                                    </p>
                                </div>
                            </div>

                            <nav className="space-y-3">
                                {getMenuItems().map((item) => (
                                    <button
                                        key={item.id}
                                        onClick={() => setActiveTab(item.id)}
                                        className={`w-full flex items-center space-x-4 px-5 py-4 rounded-2xl transition-all duration-300 font-bold ${activeTab === item.id
                                            ? 'bg-primary-50 dark:bg-primary-900/40 text-primary-700 dark:text-primary-400 shadow-sm border border-primary-100 dark:border-primary-800/50'
                                            : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700/50 hover:text-slate-900 dark:hover:text-white border border-transparent'
                                            }`}
                                    >
                                        <item.icon size={22} className={activeTab === item.id ? 'text-primary-600 dark:text-primary-400' : 'text-slate-400 dark:text-slate-500'} />
                                        <span>{item.label}</span>
                                    </button>
                                ))}
                            </nav>

                            <div className="mt-10 pt-8 border-t border-slate-100 dark:border-slate-700/80 transition-colors space-y-3">
                                <button onClick={() => setActiveTab('settings')} className={`w-full flex items-center space-x-4 px-5 py-4 rounded-2xl transition-all duration-300 font-bold ${activeTab === 'settings' ? 'bg-primary-50 dark:bg-primary-900/40 text-primary-700 dark:text-primary-400' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700/50 hover:text-slate-900 dark:hover:text-white'}`}>
                                    <Settings size={22} className={activeTab === 'settings' ? 'text-primary-600 dark:text-primary-400' : 'text-slate-400 dark:text-slate-500'} />
                                    <span>Settings</span>
                                </button>
                                <button onClick={handleLogout} className="w-full flex items-center space-x-4 px-5 py-4 rounded-2xl transition-all duration-300 font-bold text-red-600 dark:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20">
                                    <LogOut size={22} className="text-red-500 dark:text-red-400" />
                                    <span>Logout</span>
                                </button>
                            </div>
                        </div>
                    </div>

                    {/* Main Content */}
                    <div className="flex-1 lg:pl-4">
                        <div className="mb-8 flex justify-between items-center transition-colors">
                            <h1 className="text-3xl font-black text-slate-900 dark:text-white capitalize">
                                {getMenuItems().find(item => item.id === activeTab)?.label}
                            </h1>
                            {currentRole === 'buyer' && (
                                <span className="text-sm font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest bg-white dark:bg-slate-800 px-4 py-2 rounded-full border border-slate-100 dark:border-slate-700 shadow-sm">Vertexia Member</span>
                            )}
                        </div>

                        <motion.div
                            key={activeTab}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ duration: 0.3 }}
                        >
                            {renderContent()}
                        </motion.div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;

