const NotFound = () => {
    // Create some random floating elements for the background
    const floatingElements = Array.from({ length: 15 }).map((_, i) => ({
        id: i,
        size: Math.random() * 40 + 20,
        x: Math.random() * 100,
        y: Math.random() * 100,
        duration: Math.random() * 20 + 10,
        delay: Math.random() * 5,
        type: i % 3 === 0 ? 'circle' : i % 3 === 1 ? 'square' : 'triangle'
    }));

    return (
        <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden transition-colors bg-[#FDFDFD] dark:bg-[#020617] font-sans">

            {/* Mind-Fresh Relaxing Atmosphere */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none">
                {/* Soft gradient base */}
                <div className="absolute inset-0 bg-gradient-to-b from-blue-50/50 to-blue-50/50 dark:from-blue-900/10 dark:to-blue-900/10" />

                {/* Huge slow ambient glows */}
                <motion.div
                    animate={{
                        scale: [1, 1.2, 1],
                        opacity: [0.3, 0.5, 0.3],
                        x: [0, 50, 0],
                        y: [0, -50, 0]
                    }}
                    transition={{ duration: 20, repeat: Infinity, ease: "easeInOut" }}
                    className="absolute top-[-10%] left-[-10%] w-[50vw] h-[50vw] bg-blue-400/20 dark:bg-blue-600/10 rounded-full blur-[120px]"
                />
                <motion.div
                    animate={{
                        scale: [1, 1.3, 1],
                        opacity: [0.2, 0.4, 0.2],
                        x: [0, -60, 0],
                        y: [0, 60, 0]
                    }}
                    transition={{ duration: 25, repeat: Infinity, ease: "easeInOut", delay: 2 }}
                    className="absolute bottom-[-10%] right-[-10%] w-[60vw] h-[60vw] bg-blue-400/20 dark:bg-blue-600/10 rounded-full blur-[140px]"
                />

                {/* Gentle floating particles (like dust or fireflies) */}
                {Array.from({ length: 20 }).map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute bg-white dark:bg-blue-200 rounded-full shadow-[0_0_10px_rgba(255,255,255,0.8)]"
                        style={{
                            width: Math.random() * 4 + 2 + 'px',
                            height: Math.random() * 4 + 2 + 'px',
                            left: `${Math.random() * 100}%`,
                            top: `${Math.random() * 100}%`,
                            opacity: Math.random() * 0.5 + 0.2
                        }}
                        animate={{
                            y: [0, -100 - Math.random() * 100],
                            x: [0, (Math.random() - 0.5) * 50],
                            opacity: [0, 0.8, 0]
                        }}
                        transition={{
                            duration: Math.random() * 10 + 10,
                            repeat: Infinity,
                            ease: "linear",
                            delay: Math.random() * 10
                        }}
                    />
                ))}
            </div>

            <motion.div
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 1, ease: "easeOut" }}
                className="relative z-10 text-center max-w-2xl px-6 py-12 bg-white/40 dark:bg-slate-900/40 backdrop-blur-2xl rounded-[3rem] border border-white/60 dark:border-slate-800/60 shadow-[0_8px_32px_rgba(0,0,0,0.05)]"
            >
                {/* Central Relaxing Element (Smooth Orb) */}
                <div className="relative w-40 h-40 mx-auto mb-10">
                    <motion.div
                        animate={{
                            scale: [1, 1.05, 1],
                            rotate: 360
                        }}
                        transition={{
                            scale: { duration: 4, repeat: Infinity, ease: "easeInOut" },
                            rotate: { duration: 20, repeat: Infinity, ease: "linear" }
                        }}
                        className="absolute inset-0 bg-gradient-to-tr from-primary-400 to-indigo-300 dark:from-primary-600 dark:to-indigo-500 rounded-full blur-md opacity-80"
                    />
                    <div className="absolute inset-2 bg-white/90 dark:bg-[#020617]/90 rounded-full backdrop-blur-sm flex items-center justify-center border border-white/50 dark:border-white/10 shadow-inner">
                        <span className="text-5xl font-black bg-gradient-to-br from-primary-500 to-indigo-500 bg-clip-text text-transparent">404</span>
                    </div>
                </div>

                <h1 className="text-4xl md:text-5xl font-black text-slate-800 dark:text-white tracking-tight mb-4">
                    Take a Deep Breath.
                </h1>

                <p className="text-lg md:text-xl text-slate-500 dark:text-slate-400 font-medium mb-10 leading-relaxed max-w-xl mx-auto">
                    The page you're looking for has drifted away. Stay a moment to relax, or gently guide yourself back home.
                </p>

                <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                    <Link to="/" className="group relative flex items-center justify-center px-8 py-4 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-2xl font-bold shadow-lg overflow-hidden transition-transform hover:-translate-y-1 w-full sm:w-auto">
                        <span className="absolute inset-0 w-full h-full bg-gradient-to-r from-primary-500 to-indigo-500 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                        <Home size={20} className="mr-2 relative z-10 group-hover:text-white transition-colors" />
                        <span className="relative z-10 group-hover:text-white transition-colors">Return Home</span>
                    </Link>
                    <button onClick={() => window.history.back()} className="flex items-center justify-center px-8 py-4 bg-transparent border-2 border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-500 text-slate-600 dark:text-slate-300 rounded-2xl font-bold transition-all hover:-translate-y-1 w-full sm:w-auto">
                        <ArrowLeft size={20} className="mr-2" />
                        Go Back
                    </button>
                </div>
            </motion.div>
        </div>
    );
};

export default NotFound;

import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import { useDispatch } from 'react-redux';
import { addToCart } from '../store/cartSlice';
import { useCurrency } from '../context/CurrencyContext';

const ProductDetails = () => {
    const { formatPrice } = useCurrency();
    const { id } = useParams();
    const dispatch = useDispatch();
    const [quantity, setQuantity] = useState(1);
    const [activeImage, setActiveImage] = useState(0);
    const [selectedColor, setSelectedColor] = useState(0);
    const [isFavorite, setIsFavorite] = useState(false);
    const [product, setProduct] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        const fetchProduct = async () => {
            try {
                const res = await axios.get(`http://localhost:5000/api/products/find/${id}`);
                const p = res.data.data?.product || res.data?.product || res.data;

                // Format for component
                // Helper to generate hyper-specific mock data based on product title/category keywords
                const getSpecificProductData = (category, title) => {
                    const t = title ? title.toLowerCase() : '';
                    let data = {
                        gallery: [
                            'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?q=80&w=800&auto=format&fit=crop', // Default Headphone
                            'https://images.unsplash.com/photo-1583394838336-acd977736f90?q=80&w=800&auto=format&fit=crop',
                            'https://images.unsplash.com/photo-1484704849700-f032a568e944?q=80&w=800&auto=format&fit=crop',
                            'https://images.unsplash.com/photo-1629367494173-c78a56567877?q=80&w=800&auto=format&fit=crop'
                        ],
                        description: `The ${title} is designed for peak performance and elegant aesthetics. Crafted with premium materials, it ensures long-lasting durability while maintaining a lightweight profile. Whether you're upgrading your daily routine or searching for the perfect gift, this item stands out in its class for reliability and style.`,
                        insights: {
                            summary: `The ${title} is highly rated for overall quality and reliability by our custom verification engine.`,
                            pros: ["Great Quality", "Reliable Performance", "Good Value"],
                            cons: ["Limited Availability", "Basic Packaging"]
                        }
                    };

                    // Electronics Specifics
                    if (category === 'Electronics' || category === 'Electronics & Gadgets') {
                        if (t.includes('mobile') || t.includes('phone') || t.includes('s24') || t.includes('ultra') || t.includes('galaxy') || t.includes('samsung') || t.includes('iphone')) {
                            data.gallery = [
                                'https://images.unsplash.com/photo-1511707171634-5f897ff02aa9?q=80&w=800&auto=format&fit=crop',
                                'https://images.unsplash.com/photo-1592899677977-9c10ca588bb3?q=80&w=800&auto=format&fit=crop', // back camera
                                'https://images.unsplash.com/photo-1616348436168-de43ad0db179?q=80&w=800&auto=format&fit=crop', // screen
                                'https://images.unsplash.com/photo-1598327105666-5b89351aff97?q=80&w=800&auto=format&fit=crop' // lifestyle
                            ];
                            data.description = `Experience the next generation of mobile computing with the ${title}. Featuring a stunning edge-to-edge OLED display, an advanced pro-grade camera system for breathtaking low-light photography, and an all-day battery life. Built with aerospace-grade aluminum and a ceramic shield front, it's as durable as it is beautiful. Fast-charge capable and 5G ready.`;
                            data.insights = {
                                summary: `Users are obsessed with the camera quality and display of the ${title}, though some miss the inclusion of a charging brick.`,
                                pros: ["Stunning OLED Display", "Pro-Grade Camera System", "All-Day Battery"],
                                cons: ["No Charger in Box", "Fingerprint Magnet Backing"]
                            };
                        } else if (t.includes('laptop') || t.includes('computer')) {
                            data.gallery = [
                                'https://images.unsplash.com/photo-1496181133206-80ce9b88a853?q=80&w=800&auto=format&fit=crop',
                                'https://images.unsplash.com/photo-1517336714731-489689fd1ca8?q=80&w=800&auto=format&fit=crop', // open laptop
                                'https://images.unsplash.com/photo-1611186871348-b1ce696e52c9?q=80&w=800&auto=format&fit=crop', // keyboard mac
                                'https://images.unsplash.com/photo-1537498425277-c283d32ef9db?q=80&w=800&auto=format&fit=crop' // desk setup
                            ];
                            data.description = `Power through your most demanding tasks with the ${title}. Equipped with an ultra-fast multi-core processor and expansive SSD storage, this machine handles heavy video editing and multitasking without breaking a sweat. The brilliant high-resolution display accurately renders millions of colors, making it perfect for creatives. Weighing just under 3 lbs, it is the ultimate portable workstation.`;
                            data.insights = {
                                summary: `The ${title} is an absolute powerhouse for productivity, though power users noted it gets warm during intensive rendering.`,
                                pros: ["Blazing Fast Processor", "Vibrant Retina Display", "Ultra-Portable Form Factor"],
                                cons: ["Thermals can run hot", "Limited Port Selection"]
                            };
                        }
                    }

                    // Fashion Specifics
                    if (category === 'Fashion') {
                        if (t.includes('shoe') || t.includes('sneaker')) {
                            data.gallery = [
                                'https://images.unsplash.com/photo-1542291026-7eec264c27ff?q=80&w=800&auto=format&fit=crop',
                                'https://images.unsplash.com/photo-1608231387042-66d1773070a5?q=80&w=800&auto=format&fit=crop', // pair
                                'https://images.unsplash.com/photo-1514989940723-e8e51635b782?q=80&w=800&auto=format&fit=crop', // wearing
                                'https://images.unsplash.com/photo-1525966222134-fcfa99b8ae77?q=80&w=800&auto=format&fit=crop' // box
                            ];
                            data.description = `Step up your sneaker game with the ${title}. Engineered with responsive cloud-like cushioning and a breathable knit upper, these shoes provide all-day comfort for walking or running. The high-traction rubber outsole ensures grip on any surface, while the sleek modern silhouette guarantees you'll turn heads whether you're at the gym or on the streets.`;
                            data.insights = {
                                summary: `Buyers praise the incredible comfort and trendy design of the ${title}, but urge new buyers to order a half-size up for the perfect fit.`,
                                pros: ["Cloud-like Cushioning", "Breathable Knit Upper", "Versatile Style"],
                                cons: ["Runs a Half-Size Small", "White details get dirty fast"]
                            };
                        } else {
                            data.gallery = [
                                'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?q=80&w=800&auto=format&fit=crop', // fashion model
                                'https://images.unsplash.com/photo-1539008835657-9e8e9680c956?q=80&w=800&auto=format&fit=crop', // close up fabric
                                'https://images.unsplash.com/photo-1434389670869-c8873cb58c85?q=80&w=800&auto=format&fit=crop', // rack
                                'https://images.unsplash.com/photo-1483985988355-763728e1935b?q=80&w=800&auto=format&fit=crop' // shopping
                            ];
                            data.description = `Elevate your wardrobe with the elegant ${title}. Cut from premium, sustainably sourced fabrics, it drapes beautifully and feels luxuriously soft against the skin. Tailored for a modern fit, it transitions seamlessly from professional office environments to evening outings. Carefully stitched seams guarantee this piece will remain a staple in your closet for years.`;
                            data.insights = {
                                summary: `The ${title} is consistently rated highly for its luxurious feel and sophisticated cut, though it does require delicate washing.`,
                                pros: ["Luxuriously Soft Fabric", "Flattering Modern Fit", "Sustainably Sourced"],
                                cons: ["Dry Clean or Hand Wash Only", "Wrinkles easily if folded"]
                            };
                        }
                    }

                    // Beauty Specifics
                    if (category === 'Beauty') {
                        data.gallery = [
                            'https://images.unsplash.com/photo-1596462502278-27bfdc403348?q=80&w=800&auto=format&fit=crop',
                            'https://images.unsplash.com/photo-1620916566398-39f1143ab7be?q=80&w=800&auto=format&fit=crop', // application
                            'https://images.unsplash.com/photo-1571781926291-c477eb3af723?q=80&w=800&auto=format&fit=crop', // texture
                            'https://images.unsplash.com/photo-1556228578-0d85b1a4d571?q=80&w=800&auto=format&fit=crop' // arrangement
                        ];
                        data.description = `Achieve a flawless, radiant glow with the ${title}. Infused with potent antioxidants and hydrating botanicals, this formula nourishes deeply while providing a stunning finish. Completely cruelty-free and formulated without parabens or sulfates, it is safe for even the most sensitive skin types. Experience a lightweight texture that absorbs instantly.`;
                        data.insights = {
                            summary: `Customers love how radiant their skin looks after using the ${title}. The cruelty-free formula is a huge hit.`,
                            pros: ["Provides Radiant Glow", "Cruelty & Paraben Free", "Lightweight Texture"],
                            cons: ["Relatively Small Bottle", "Slight floral scent (subjective)"]
                        };
                    }

                    return data;
                };

                const specificData = getSpecificProductData(p.category?.name || 'Uncategorized', p.title);

                const formattedProduct = {
                    id: p._id,
                    title: p.title || 'Vertex Product',
                    price: p.price,
                    originalPrice: p.discountedPrice ? p.price : p.price * 1.2,
                    description: specificData.description,
                    rating: p.ratings?.average || 4.5,
                    reviews: p.ratings?.count || 120,
                    inventory: p.inventory,
                    brand: p.specifications?.Brand || 'Vertex',
                    category: p.category?.name || 'Uncategorized',
                    images: specificData.gallery, // Inject the 4-image array
                    features: [
                        'Premium quality materials',
                        'Durable and long-lasting',
                        'Eco-friendly packaging',
                        'Fast shipping available'
                    ],
                    specs: p.specifications || { 'Weight': 'Standard', 'Material': 'Mixed' },
                    colors: ['#0f172a', '#e2e8f0', '#3b82f6'],
                    aiInsights: specificData.insights // Inject the specific insights
                };

                // If the product returned already has discounted price logic setup, apply it
                if (p.discountedPrice) {
                    formattedProduct.price = p.discountedPrice;
                    formattedProduct.originalPrice = p.price;
                }

                setProduct(formattedProduct);
                setLoading(false);
            } catch (err) {
                console.error('Failed to fetch product details:', err);
                setError('Failed to load product details.');
                setLoading(false);
            }
        };

        fetchProduct();
    }, [id]);

    useEffect(() => {
        if (product) {
            document.title = `${product.title} | Vertexia`;
            const metaDescription = document.querySelector('meta[name="description"]');
            if (metaDescription) {
                metaDescription.setAttribute("content", `Buy ${product.title} at Vertexia. Read verified AI insights, customer reviews, and get the best price.`);
            }
        }
    }, [product]);

    if (loading) return <div className="min-h-screen flex items-center justify-center bg-[#F8FAFC] dark:bg-[#020617]"><p className="text-xl dark:text-white font-bold animate-pulse">Loading Product Details...</p></div>;
    if (error) return <div className="min-h-screen flex items-center justify-center bg-[#F8FAFC] dark:bg-[#020617]"><p className="text-xl text-red-500 font-bold">{error}</p></div>;
    if (!product) return <div className="min-h-screen flex items-center justify-center bg-[#F8FAFC] dark:bg-[#020617]"><p className="text-xl text-gray-500 font-bold">Product not found.</p></div>;

    const discount = Math.round(((product.originalPrice - product.price) / product.originalPrice) * 100);
    const availableStock = Math.max(0, product.inventory - quantity);

    const handleShare = async () => {
        const shareData = {
            title: `${product.title} | Vertexia`,
            text: `Check out this amazing ${product.title} at Vertexia!`,
            url: window.location.href
        };
        try {
            if (navigator.share) {
                await navigator.share(shareData);
            } else {
                await navigator.clipboard.writeText(window.location.href);
                alert("Link copied to clipboard!");
            }
        } catch (err) {
            console.error("Error sharing:", err);
        }
    };

    return (
        <div className="bg-[#F8FAFC] dark:bg-[#020617] min-h-screen transition-colors duration-300 relative overflow-hidden">
            {/* Ambient Background Glowing Orbs */}
            <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-primary-400/20 rounded-full blur-[120px] pointer-events-none" />
            <div className="absolute top-[40%] right-[-5%] w-96 h-96 bg-fuchsia-500/10 rounded-full blur-[120px] pointer-events-none" />

            {/* Breadcrumb */}
            <div className="bg-white dark:bg-[#020617] border-b border-slate-100 dark:border-slate-800 transition-colors">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-3">
                    <nav className="flex text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">
                        <Link to="/" className="hover:text-primary-600 dark:hover:text-primary-400 transition-colors">Home</Link>
                        <span className="mx-3 text-slate-300 dark:text-slate-600">/</span>
                        <Link to="/products" className="hover:text-primary-600 dark:hover:text-primary-400 transition-colors">Products</Link>
                        <span className="mx-3 text-slate-300 dark:text-slate-600">/</span>
                        <span className="text-slate-900 dark:text-slate-300 truncate">{product.category}</span>
                    </nav>
                </div>
            </div>

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
                <div className="lg:grid lg:grid-cols-2 lg:gap-x-12 xl:gap-x-16">

                    {/* 3D Product Workbench Container (Left Column) */}
                    <div className="relative z-10 w-full rounded-[2.5rem] overflow-hidden shadow-2xl shadow-blue-500/10 dark:shadow-blue-500/5">
                        <ProductWorkbench product={product} selectedColor={product.colors[selectedColor]} />
                    </div>

                    {/* Product Info Container (Right Column) */}
                    <motion.div
                        initial={{ opacity: 0, x: 30 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.5, delay: 0.1 }}
                        className="mt-10 px-4 sm:px-0 lg:mt-0"
                    >
                        <div className="mb-6 flex justify-between items-start">
                            <div>
                                <p className="text-sm text-primary-600 dark:text-primary-400 font-extrabold uppercase tracking-widest mb-3 bg-primary-50 dark:bg-primary-900/30 inline-block px-3 py-1 rounded-lg transition-colors">{product.brand}</p>
                                <h1 className="text-3xl sm:text-4xl lg:text-5xl font-black text-slate-900 dark:text-white tracking-tight leading-[1.1] mb-5">
                                    {product.title}
                                </h1>
                            </div>
                            <button onClick={handleShare} className="p-3 bg-slate-50 dark:bg-slate-800 text-slate-500 dark:text-slate-400 hover:text-primary-600 dark:hover:text-primary-400 rounded-full transition-all border border-slate-200 dark:border-slate-700 hover:border-primary-200 dark:hover:border-primary-800 shadow-sm" aria-label="Share product">
                                <Share2 size={20} />
                            </button>
                        </div>

                        <div className="flex items-center">
                            <div className="flex items-center text-yellow-400 bg-yellow-50 px-2 py-1 rounded-md">
                                <Star size={18} className="fill-current" />
                                <span className="ml-1.5 text-sm font-black text-yellow-700">{product.rating}</span>
                            </div>
                            <span className="mx-4 text-gray-300">|</span>
                            <a href="#reviews" className="text-sm font-bold text-gray-500 hover:text-primary-600 transition-colors underline decoration-dashed decoration-gray-300 underline-offset-4">
                                Based on {product.reviews.toLocaleString()} verified ratings
                            </a>
                        </div>

                        <motion.div
                            initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.4 }}
                            className="relative overflow-hidden bg-gradient-to-br from-blue-50/80 to-blue-50/80 dark:from-blue-900/30 dark:to-blue-900/30 backdrop-blur-md rounded-[2rem] p-8 mb-8 border border-white/50 dark:border-blue-500/20 shadow-xl group"
                        >
                            <div className="absolute top-0 right-0 w-64 h-64 bg-primary-400/10 dark:bg-primary-500/20 rounded-full blur-3xl group-hover:bg-primary-400/20 transition-colors duration-700 pointer-events-none" />
                            <div className="relative z-10">
                                <div className="flex items-center space-x-2 text-blue-700 dark:text-blue-400 font-black text-sm uppercase tracking-widest mb-4">
                                    <Sparkles size={18} className="animate-pulse" />
                                    <span>AI Review Insights</span>
                                </div>
                                <p className="text-sm text-slate-700 dark:text-slate-300 leading-relaxed font-medium mb-6">
                                    {product.aiInsights.summary}
                                </p>

                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                                    <div className="bg-white/60 dark:bg-slate-900/40 p-5 rounded-2xl border border-white/50 dark:border-slate-700/50 hover:shadow-lg hover:shadow-green-500/5 transition-shadow">
                                        <h5 className="text-[11px] font-black text-green-700 dark:text-green-400 uppercase tracking-widest mb-4 flex items-center bg-green-100/50 dark:bg-green-900/30 w-fit px-3 py-1.5 rounded-lg border border-green-200/50 dark:border-green-800/50">
                                            <ThumbsUp size={14} className="mr-2" /> Advantages
                                        </h5>
                                        <ul className="space-y-2.5">
                                            {product.aiInsights.pros.map((pro, idx) => (
                                                <li key={idx} className="flex items-center text-xs font-bold text-slate-700 dark:text-slate-300">
                                                    <span className="w-1.5 h-1.5 rounded-full bg-green-500 mr-2 flex-shrink-0" /> {pro}
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                    <div className="bg-white/60 dark:bg-slate-900/40 p-5 rounded-2xl border border-white/50 dark:border-slate-700/50 hover:shadow-lg hover:shadow-red-500/5 transition-shadow">
