                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                            {[
                                { name: "Sarah Jenkins", text: "Absolutely blown away by the quality. It exceeded all my expectations, especially the finish and attention to detail. Would highly recommend to anyone on the fence.", rate: 5, date: "Oct 12, 2025" },
                                { name: "Michael Chen", text: "Solid product. Does exactly what it promises. The shipping was fast and the packaging was completely secure. Only giving 4 stars because the instruction manual could be clearer.", rate: 4, date: "Sep 28, 2025" },
                                { name: "Elena Rodriguez", text: "This is my third purchase from Vertexia and they never disappoint. The premium feel of this item is unmatched at this price point. Flawless execution.", rate: 5, date: "Nov 04, 2025" }
                            ].map((review, i) => (
