                                        <span className="bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 border border-green-200 dark:border-green-800 text-[10px] font-black uppercase px-2 py-0.5 rounded-full ml-auto">Verified</span>
                                    </div>
