};

export default ProductDetails;

import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import axios from 'axios';
import { useCurrency } from '../context/CurrencyContext';

// Categories will be fixed to match DB or fetched dynamically. Let's fetch products and map dynamically.
// We'll calculate unique categories from the fetched data.
const containerVariants = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: { staggerChildren: 0.1 }
    }
};

const itemVariants = {
    hidden: { opacity: 0, scale: 0.8 },
    show: { opacity: 1, scale: 1, transition: { type: "spring", stiffness: 300, damping: 24 } },
    exit: { opacity: 0, scale: 0.5, transition: { duration: 0.2 } }
};

const SUBCATEGORIES_MAP = {
    'Electronics & Gadgets': ['Smartphones', 'Tablets', 'Laptops', 'Wearables', 'Home Appliances'],
    'Fashion & Apparel': ['Men', 'Women', 'Footwear', 'Accessories'],
    'Home, Kitchen, & Furniture': ['Kitchen & Dining', 'Furniture', 'Home Decor'],
    'Health, Beauty, & Personal Care': ['Skincare', 'Haircare', 'Makeup', 'Wellness'],
    'Groceries & Pantry': ['Fruits & Vegetables', 'Staples', 'Beverages', 'Dairy & Bakery'],
    'Toys, Hobbies, & Books': ['Toys', 'Books', 'Hobbies'],
};

const CATEGORY_COLORS = {
    'All': 'from-slate-400 to-slate-500 text-slate-700 dark:text-slate-300',
    'Electronics & Gadgets': 'from-blue-400 to-indigo-500 text-blue-700 dark:text-blue-300',
    'Fashion & Apparel': 'from-pink-400 to-rose-500 text-rose-700 dark:text-rose-300',
    'Health, Beauty, & Personal Care': 'from-purple-400 to-fuchsia-500 text-fuchsia-700 dark:text-fuchsia-300',
    'Home, Kitchen, & Furniture': 'from-emerald-400 to-teal-500 text-teal-700 dark:text-teal-300',
    'Groceries & Pantry': 'from-orange-400 to-amber-500 text-orange-700 dark:text-orange-300',
    'Toys, Hobbies, & Books': 'from-blue-400 to-blue-500 text-blue-700 dark:text-blue-300',
};

const Products = () => {
    const { formatPrice } = useCurrency();
    const location = useLocation();
    const initialCategory = location.state?.selectedCategory ? [location.state.selectedCategory] : [];

    const [products, setProducts] = useState([]);
    const [categories, setCategories] = useState(['All']);
    const [loading, setLoading] = useState(true);
    const [viewMode, setViewMode] = useState('grid');
    const [isSortOpen, setIsSortOpen] = useState(false);
    const [isFilterOpen, setIsFilterOpen] = useState(false);
    const [sortBy, setSortBy] = useState('recommended');
    const [selectedCategories, setSelectedCategories] = useState(initialCategory);
    const [selectedSubcategories, setSelectedSubcategories] = useState([]);
    const [selectedBrands, setSelectedBrands] = useState([]);
    const [inStockOnly, setInStockOnly] = useState(false);
    const [priceRange, setPriceRange] = useState({ min: '', max: '' });
    const [minRating, setMinRating] = useState(0);
    const [currentPage, setCurrentPage] = useState(1);
    const itemsPerPage = 9;

    useEffect(() => {
        // Reset to page 1 when any filter or sort changes
        setCurrentPage(1);
    }, [selectedCategories, selectedSubcategories, selectedBrands, inStockOnly, priceRange, minRating, sortBy]);

    // SEO Head Title Update
    useEffect(() => {
        document.title = "Explore Products | Vertexia - Premium E-commerce";
        const metaDescription = document.querySelector('meta[name="description"]');
        if (metaDescription) {
            metaDescription.setAttribute("content", "Browse our huge collection of premium electronics, fashion, beauty, and home items at Vertexia.");
        }
    }, []);

    // Ensure we start at the top of the page when coming from another route
    useEffect(() => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }, []);

    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const [res, catRes] = await Promise.all([
                    axios.get('http://localhost:5000/api/products'),
                    axios.get('http://localhost:5000/api/categories').catch(() => ({ data: [] }))
                ]);

                const catData = catRes.data.data?.categories || catRes.data?.categories || catRes.data || [];
                const catMap = {};
                (Array.isArray(catData) ? catData : []).forEach(c => {
                    if (c._id) catMap[c._id] = c.name;
                });

                const pData = res.data.data?.products || res.data?.products || res.data;
                const pList = Array.isArray(pData) ? pData : [];

                const formattedProducts = pList.map(p => {
                    const resolvedCatName = p.category?.name || catMap[typeof p.category === 'string' ? p.category : p.category?._id] || 'Uncategorized';
                    return {
                        id: p._id,
                        title: p.title,
                        price: p.discountedPrice || p.price,
                        originalPrice: p.price,
                        rating: p.ratings?.average || 4.5,
                        reviews: p.ratings?.count || 120,
                        inventory: p.inventory !== undefined ? p.inventory : Math.floor(Math.random() * 20),
                        brand: p.specifications?.Brand || (resolvedCatName === 'Electronics & Gadgets' ? 'TechCore' : resolvedCatName === 'Fashion & Apparel' ? 'UrbanFit' : 'Vertex'),
                        image: (p.images && p.images.length > 0) ? p.images[0].url : 'https://via.placeholder.com/800',
                        category: resolvedCatName,
                        subCategory: p.subCategory || ''
                    };
                });
                setProducts(formattedProducts);

                // Extract unique categories
                const uniqueCategories = ['All', ...new Set(formattedProducts.map(p => p.category))];
                setCategories(uniqueCategories);
                setLoading(false);
            } catch (error) {
                console.error('Failed to fetch products:', error);
                setLoading(false);
            }
        };

        fetchProducts();
    }, []);

    const handleCategoryChange = (cat) => {
        if (cat === 'All') {
            setSelectedCategories([]);
            setSelectedSubcategories([]);
            return;
        }

        // Accordion logic: Selecting a new category overwrites the previous ones,
        // and if it's the exact same category, it toggles it off.
        setSelectedCategories(prev => {
            if (prev.length === 1 && prev[0] === cat) {
                setSelectedSubcategories([]);
                return []; // Toggle off if clicking the already open one
            } else {
                setSelectedSubcategories([]); // Clear subcategories when switching
                return [cat]; // Only allow one category to be open at a time
            }
        });
    };

    const handleSubcategoryChange = (sub) => {
        setSelectedSubcategories(prev =>
            prev.includes(sub) ? prev.filter(s => s !== sub) : [...prev, sub]
        );
    };

    const handleBrandChange = (brand) => {
        setSelectedBrands(prev =>
            prev.includes(brand) ? prev.filter(b => b !== brand) : [...prev, brand]
        );
    };

    const filteredProducts = React.useMemo(() => {
        let result = products.filter(product => {
            let matchCat = selectedCategories.length === 0 || selectedCategories.includes('All') || selectedCategories.includes(product.category);

            let matchSub = true;
            if (selectedSubcategories.length > 0) {
                // Check if product's subCategory exactly matches, or if title contains it (fallback)
                matchSub = selectedSubcategories.some(sub =>
                    (product.subCategory && product.subCategory.toLowerCase() === sub.toLowerCase()) ||
                    product.title.toLowerCase().includes(sub.toLowerCase())
                );
            }

            let matchBrand = selectedBrands.length === 0 || selectedBrands.includes(product.brand);
            let matchStock = !inStockOnly || product.inventory > 0;

            let matchPrice = true;
            if (priceRange.min !== '') matchPrice = matchPrice && product.price >= Number(priceRange.min);
            if (priceRange.max !== '') matchPrice = matchPrice && product.price <= Number(priceRange.max);

            let matchRating = product.rating >= minRating;

            return matchCat && matchSub && matchBrand && matchStock && matchPrice && matchRating;
        });

        if (sortBy === 'price-low') {
            result.sort((a, b) => a.price - b.price);
        } else if (sortBy === 'price-high') {
            result.sort((a, b) => b.price - a.price);
        } else if (sortBy === 'rating') {
            result.sort((a, b) => b.rating - a.rating);
        }

        return result;
    }, [products, selectedCategories, selectedSubcategories, selectedBrands, inStockOnly, priceRange, minRating, sortBy]);

    const ALL_BRANDS = React.useMemo(() => [...new Set(products.map(p => p.brand))], [products]);

    if (loading) {
        return (
            <div className="bg-transparent min-h-screen py-10 flex justify-center items-center transition-colors duration-300">
                <div className="flex flex-col flex-1 max-w-7xl mx-auto px-4 w-full">
                    {/* Skeleton Loader matching the product grid layout */}
                    <div className="animate-pulse flex space-x-4">
                        <div className="flex-1 space-y-6 py-1">
                            <div className="h-8 bg-slate-200 dark:bg-slate-700 rounded w-1/4"></div>
                            <div className="space-y-3">
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                                    {[...Array(6)].map((_, i) => (
                                        <div key={i} className="h-80 bg-slate-200 dark:bg-slate-800 rounded-3xl"></div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-transparent min-h-screen py-10 transition-colors duration-300">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

                {/* Page Header */}
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 pb-6 border-b border-gray-200 gap-4">
                    <div>
                        <h1 className="text-4xl font-black text-gray-900 dark:text-white tracking-tight">All Products</h1>
                        <p className="mt-2 text-sm text-gray-500 dark:text-gray-400 font-medium">Showing {filteredProducts.length} items</p>
                    </div>

                    <div className="mt-2 md:mt-0 flex flex-wrap items-center gap-4">
                        <div className="relative inline-block text-left w-full sm:w-auto">
                            <button onClick={() => setIsSortOpen(!isSortOpen)} className="flex items-center justify-between w-64 px-4 py-2.5 bg-white dark:bg-slate-800 dark:border-slate-700 border border-gray-200 rounded-xl shadow-sm text-sm font-bold text-gray-700 dark:text-slate-300 hover:border-primary-500 dark:hover:border-primary-400 focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all">
                                <span className="flex items-center truncate">
                                    <Sparkles size={14} className="mr-2 text-blue-500 flex-shrink-0" />
                                    Sort: {sortBy === 'recommended' ? 'AI Recommended' : sortBy === 'price-low' ? 'Price: Low to High' : sortBy === 'price-high' ? 'Price: High to Low' : 'Highest Rated'}
                                </span>
                                <ChevronDown size={16} className="ml-2 text-gray-400 flex-shrink-0" />
                            </button>
                            {isSortOpen && (
                                <div className="origin-top-right absolute right-0 mt-2 w-64 rounded-xl shadow-lg bg-white dark:bg-slate-800 ring-1 ring-black dark:ring-slate-700 ring-opacity-5 z-20 border border-gray-100 dark:border-slate-700 overflow-hidden">
                                    <div className="py-1" role="menu">
                                        <button onClick={() => { setSortBy('recommended'); setIsSortOpen(false) }} className={`block px-4 py-2.5 text-sm font-medium w-full text-left ${sortBy === 'recommended' ? 'bg-primary-50 text-primary-700 dark:bg-primary-900/40 dark:text-primary-400' : 'text-gray-700 dark:text-slate-300 hover:bg-gray-50 dark:hover:bg-slate-700'}`}>AI Recommended</button>
                                        <button onClick={() => { setSortBy('price-low'); setIsSortOpen(false) }} className={`block px-4 py-2.5 text-sm font-medium w-full text-left ${sortBy === 'price-low' ? 'bg-primary-50 text-primary-700 dark:bg-primary-900/40 dark:text-primary-400' : 'text-gray-700 dark:text-slate-300 hover:bg-gray-50 dark:hover:bg-slate-700'}`}>Price: Low to High</button>
                                        <button onClick={() => { setSortBy('price-high'); setIsSortOpen(false) }} className={`block px-4 py-2.5 text-sm font-medium w-full text-left ${sortBy === 'price-high' ? 'bg-primary-50 text-primary-700 dark:bg-primary-900/40 dark:text-primary-400' : 'text-gray-700 dark:text-slate-300 hover:bg-gray-50 dark:hover:bg-slate-700'}`}>Price: High to Low</button>
                                        <button onClick={() => { setSortBy('rating'); setIsSortOpen(false) }} className={`block px-4 py-2.5 text-sm font-medium w-full text-left ${sortBy === 'rating' ? 'bg-primary-50 text-primary-700 dark:bg-primary-900/40 dark:text-primary-400' : 'text-gray-700 dark:text-slate-300 hover:bg-gray-50 dark:hover:bg-slate-700'}`}>Highest Rated</button>
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="flex flex-shrink-0 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl shadow-sm p-1 ml-auto sm:ml-0">
                            <button
                                onClick={() => setViewMode('grid')}
                                className={`p-2 rounded-lg transition-colors ${viewMode === 'grid' ? 'bg-primary-50 dark:bg-primary-900/40 text-primary-600 dark:text-primary-400 shadow-sm' : 'text-gray-400 dark:text-slate-400 hover:text-gray-900 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-slate-700'}`}
                            >
                                <Grid size={18} />
                            </button>
                            <button
                                onClick={() => setViewMode('list')}
                                className={`p-2 rounded-lg transition-colors ${viewMode === 'list' ? 'bg-primary-50 dark:bg-primary-900/40 text-primary-600 dark:text-primary-400 shadow-sm' : 'text-gray-400 dark:text-slate-400 hover:text-gray-900 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-slate-700'}`}
                            >
                                <List size={18} />
                            </button>
                        </div>
                    </div>
                </div>

                <div className="flex flex-col lg:flex-row gap-8">

                    {/* Sidebar Filters */}
                    <div className="w-full lg:w-72 flex-shrink-0">
                        {/* Mobile Filter Toggle */}
                        <div className="lg:hidden mb-4">
                            <button
                                onClick={() => setIsFilterOpen(!isFilterOpen)}
                                className="w-full flex items-center justify-between px-4 py-3 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl shadow-sm font-bold text-gray-700 dark:text-slate-300"
                            >
                                <span className="flex items-center"><Filter size={18} className="mr-2 text-primary-600 dark:text-primary-400" /> Filters & Sorting</span>
                                <ChevronDown size={18} className={`transform transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} />
                            </button>
