                        <div className={`${isFilterOpen ? 'block' : 'hidden'} lg:block bg-white dark:bg-gray-800 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700 p-6 lg:sticky lg:top-24 transition-colors max-h-[85vh] overflow-y-auto [&::-webkit-scrollbar]:w-1.5 [&::-webkit-scrollbar-track]:bg-transparent [&::-webkit-scrollbar-thumb]:bg-slate-200 dark:[&::-webkit-scrollbar-thumb]:bg-slate-700 [&::-webkit-scrollbar-thumb]:rounded-full`}>
                            <div className="flex items-center justify-between mb-8">
                                <h2 className="text-lg font-black text-gray-900 dark:text-white flex items-center tracking-tight">
                                    <Filter size={18} className="mr-2 text-primary-600 dark:text-primary-400" /> Filters
                                </h2>
                                <button onClick={() => { setSelectedCategories([]); setSelectedSubcategories([]); setPriceRange({ min: '', max: '' }); setMinRating(0); setSortBy('recommended'); }} className="text-xs font-bold bg-primary-50 text-primary-600 hover:bg-primary-100 dark:bg-primary-900/30 dark:text-primary-400 px-3 py-1.5 rounded-full dark:hover:bg-primary-900/50 transition-colors shadow-sm">Clear All</button>
                            </div>

                            <div className="space-y-8">
                                {/* Categories */}
                                <div>
                                    <h3 className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-4 flex items-center"><Tags size={14} className="mr-2" /> Categories</h3>
                                    <div className="space-y-4">
                                        {categories.map((cat, i) => {
                                            const isSelected = cat === 'All' ? selectedCategories.length === 0 : selectedCategories.includes(cat);
                                            const gradient = CATEGORY_COLORS[cat] ? CATEGORY_COLORS[cat].split(' ')[0] + ' ' + CATEGORY_COLORS[cat].split(' ')[1] : 'from-primary-400 to-indigo-500';
                                            const textColor = CATEGORY_COLORS[cat] ? CATEGORY_COLORS[cat].split(' ').slice(2).join(' ') : 'text-primary-700 dark:text-primary-300';
                                            const hasSubcategories = SUBCATEGORIES_MAP[cat] && SUBCATEGORIES_MAP[cat].length > 0;

                                            // Ensure "All" doesn't render subcategories
                                            const showSubs = isSelected && hasSubcategories && cat !== 'All';

                                            return (
                                                <div key={i} className="flex flex-col">
                                                    <button
                                                        onClick={() => handleCategoryChange(cat)}
                                                        className={`flex items-center justify-between w-full px-4 py-3 rounded-2xl transition-all duration-300 font-bold text-sm ${isSelected
                                                            ? `bg-gradient-to-r ${gradient} text-white shadow-lg transform scale-[1.02]`
                                                            : `bg-slate-50 dark:bg-slate-800/50 ${textColor} hover:bg-slate-100 dark:hover:bg-slate-800 border border-slate-100 dark:border-slate-700/50 hover:shadow-md`
                                                            }`}
                                                    >
                                                        <span className="truncate pr-2">{cat}</span>
                                                        {hasSubcategories && cat !== 'All' && (
                                                            <ChevronDown size={16} className={`flex-shrink-0 transition-transform duration-300 ${isSelected ? 'rotate-180 text-white' : 'text-slate-400'}`} />
                                                        )}
                                                    </button>

                                                    {/* Subcategories (Animated expand) */}
                                                    <AnimatePresence>
                                                        {showSubs && (
                                                            <motion.div
                                                                initial={{ height: 0, opacity: 0 }}
                                                                animate={{ height: "auto", opacity: 1 }}
                                                                exit={{ height: 0, opacity: 0 }}
                                                                transition={{ duration: 0.3 }}
                                                                className="overflow-hidden ml-4 mt-2 border-l-2 border-slate-100 dark:border-slate-700/50 pl-4 space-y-2 flex flex-col"
                                                            >
                                                                {SUBCATEGORIES_MAP[cat].map(sub => {
                                                                    const isSubSelected = selectedSubcategories.includes(sub);
                                                                    return (
                                                                        <button
                                                                            key={sub}
                                                                            onClick={() => handleSubcategoryChange(sub)}
                                                                            className={`text-left text-sm font-bold px-3 py-2 rounded-xl transition-all ${isSubSelected
                                                                                ? `bg-slate-900 dark:bg-white text-white dark:text-slate-900 shadow-md`
                                                                                : `text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800`
                                                                                }`}
                                                                        >
                                                                            {sub}
                                                                        </button>
                                                                    );
                                                                })}
                                                            </motion.div>
                                                        )}
                                                    </AnimatePresence>
                                                </div>
                                            );
