                                </div>

                                {/* Price Range */}
                                <div className="pt-8 border-t border-gray-100 dark:border-slate-700">
                                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4">Price Range</h3>
                                    <div className="flex items-center space-x-4">
                                        <input type="number" value={priceRange.min} onChange={(e) => setPriceRange(prev => ({ ...prev, min: e.target.value }))} placeholder="Min" className="w-full px-3 py-2.5 bg-gray-50 dark:bg-slate-700 border border-gray-200 dark:border-slate-600 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-primary-500 focus:bg-white dark:focus:bg-slate-800 transition-all dark:text-white" />
                                        <span className="text-gray-400 font-medium">-</span>
                                        <input type="number" value={priceRange.max} onChange={(e) => setPriceRange(prev => ({ ...prev, max: e.target.value }))} placeholder="Max" className="w-full px-3 py-2.5 bg-gray-50 dark:bg-slate-700 border border-gray-200 dark:border-slate-600 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-primary-500 focus:bg-white dark:focus:bg-slate-800 transition-all dark:text-white" />
                                    </div>
                                </div>

                                {/* Brands */}
                                <div className="pt-8 border-t border-gray-100 dark:border-slate-700">
                                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4">Brands</h3>
