                                        />
                                        <span className="ml-3 text-sm font-bold text-gray-600 dark:text-slate-300">In Stock Ready</span>
                                    </label>
                                </div>

                                {/* Ratings */}
                                <div className="pt-8 border-t border-gray-100 dark:border-slate-700">
                                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4">Customer Rating</h3>
                                    <div className="space-y-3">
                                        {[4, 3, 2, 1].map((rating) => (
                                            <label key={rating} className="flex items-center group cursor-pointer">
                                                <input
                                                    type="radio"
                                                    name="rating"
                                                    checked={minRating === rating}
                                                    onChange={() => setMinRating(rating)}
                                                    className="w-5 h-5 text-primary-600 border-gray-300 dark:border-slate-600 dark:bg-slate-700 focus:ring-primary-500 transition-colors"
                                                />
                                                <span className="ml-3 flex items-center">
                                                    {[...Array(5)].map((_, i) => (
                                                        <Star key={i} size={16} className={i < rating ? 'text-yellow-400 fill-current' : 'text-gray-200 dark:text-slate-600'} />
                                                    ))}
                                                    <span className="ml-2 text-sm font-bold text-gray-600 dark:text-slate-300">& Up</span>
                                                </span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Product Grid Layout */}
                    <div className="flex-1">
                        <motion.div
                            variants={containerVariants}
                            initial="hidden"
                            animate="show"
                            className={viewMode === 'grid'
                                ? "grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 grid-flow-row-dense"
                                : "flex flex-col space-y-6"
                            }>
                            {filteredProducts.length === 0 ? (
                                <div className="col-span-full w-full text-center py-20 bg-white dark:bg-slate-800 rounded-3xl border border-slate-100 dark:border-slate-700/80 shadow-md transition-colors flex flex-col items-center justify-center">
                                    <div className="w-20 h-20 bg-slate-50 dark:bg-slate-900/50 rounded-full flex items-center justify-center mb-6 border border-slate-100 dark:border-slate-700">
                                        <Filter size={32} className="text-slate-300 dark:text-slate-600" />
                                    </div>
                                    <p className="text-xl font-black text-slate-800 dark:text-white mb-2">No products match your filters.</p>
                                    <p className="text-slate-500 dark:text-slate-400 font-medium mb-6">Try adjusting your categories or price range.</p>
                                    <button onClick={() => { setSelectedCategories([]); setSelectedSubcategories([]); setPriceRange({ min: '', max: '' }); setMinRating(0); }} className="px-6 py-3 bg-primary-600 hover:bg-primary-500 text-white rounded-xl shadow-lg font-bold transition-all transform hover:-translate-y-1">Clear all filters</button>
                                </div>
                            ) : (
                                <AnimatePresence mode="popLayout">
                                    {filteredProducts.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map((product) => {
                                        const cardColorClass = CATEGORY_COLORS[product.category] || 'from-slate-400 to-slate-500 text-slate-700 dark:text-slate-300';
                                        const borderGlowClass = cardColorClass.split(' ')[0].replace('from-', 'group-hover/card:border-');
                                        const shadowGlowClass = cardColorClass.split(' ')[1].replace('to-', 'group-hover/card:shadow-') + '/20';
                                        const badgeBg = cardColorClass.split(' ')[0].replace('from-', 'bg-');

                                        return (
                                            <motion.div key={product.id} layout initial="hidden" animate="show" exit="exit" variants={itemVariants} className={viewMode === 'list' ? 'col-span-full' : ''}>
                                                <Tilt tiltMaxAngleX={8} tiltMaxAngleY={8} scale={1.02} transitionSpeed={2500} className={`group/card ${viewMode === 'list' ? 'h-52 w-full' : 'flex flex-col h-full'} relative`}>
                                                    <div className={`flex ${viewMode === 'list' ? 'flex-row' : 'flex-col'} h-full bg-white/70 dark:bg-[#020617]/70 backdrop-blur-xl rounded-[2rem] overflow-hidden border border-slate-200/50 dark:border-white/5 shadow-xl hover:shadow-2xl hover:border-slate-300 dark:hover:border-white/20 transition-all duration-500 cursor-pointer`} onClick={() => window.location.href = `/products/${product.id}`}>

                                                        {/* Image Container */}
                                                        <div className={`relative bg-slate-50 dark:bg-[#050811] overflow-hidden ${viewMode === 'list' ? 'w-1/3 min-w-[200px] border-r border-slate-100 dark:border-white/5' : 'h-64 border-b border-slate-100 dark:border-white/5'}`}>
                                                            {/* Category Badge */}
                                                            <div className="absolute top-4 left-4 z-20">
                                                                <p className={`text-[10px] text-white font-black uppercase tracking-widest ${badgeBg} backdrop-blur-md border border-white/20 px-3 py-1.5 rounded-xl shadow-lg`}>
                                                                    {product.category}
                                                                </p>
                                                            </div>

                                                            {/* Image */}
                                                            <img
                                                                src={product.image}
                                                                alt={product.title}
                                                                className="w-full h-full object-cover dark:brightness-90 group-hover/card:scale-110 transition-all duration-700 ease-[cubic-bezier(0.25,0.46,0.45,0.94)]"
                                                            />

                                                            {/* Hover Gradient Overlay */}
                                                            <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent opacity-0 group-hover/card:opacity-100 transition-opacity duration-500 pointer-events-none" />
                                                        </div>

                                                        {/* Card Content */}
                                                        <div className={`flex flex-col flex-1 p-6 ${viewMode === 'list' ? 'justify-center' : ''}`}>
                                                            <div className="flex justify-between items-start mb-2">
                                                                <div className="flex items-center text-yellow-400 bg-yellow-50 dark:bg-yellow-900/20 px-2 py-1 rounded-md border border-yellow-200 dark:border-yellow-700/50">
                                                                    <Star size={14} className="fill-current" />
                                                                    <span className="ml-1 text-xs font-black text-yellow-700 dark:text-yellow-500">{product.rating}</span>
                                                                </div>
                                                                <span className="text-xs font-bold text-slate-500 dark:text-slate-400">{product.reviews} Verification Reviews</span>
                                                            </div>

                                                            {/* Title */}
                                                            <h3 className={`text-xl font-black text-slate-900 dark:text-white leading-snug line-clamp-2 mb-3 group-hover/card:${cardColorClass.split(' ')[2]} transition-colors`}>
                                                                <Link to={`/products/${product.id}`}>
                                                                    <span aria-hidden="true" className="absolute inset-0 z-10" />
                                                                    {product.title}
                                                                </Link>
                                                            </h3>

                                                            <div className="mt-auto flex items-center justify-between">
                                                                <div>
                                                                    <p className="text-2xl font-black text-slate-900 dark:text-white tracking-tighter">{formatPrice(product.price)}</p>
                                                                    {product.originalPrice > product.price && (
                                                                        <p className="text-sm text-slate-400 line-through font-bold">{formatPrice(product.originalPrice)}</p>
                                                                    )}
                                                                </div>
                                                                <button className={`pointer-events-none relative z-20 flex-shrink-0 bg-slate-900 dark:bg-white text-white dark:text-slate-900 w-10 h-10 rounded-full flex items-center justify-center transform group-hover/card:scale-110 hover:!bg-primary-600 hover:text-white transition-all shadow-md active:scale-95`}>
                                                                    <ChevronRight size={20} className="ml-0.5" />
                                                                </button>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </Tilt>
                                            </motion.div>
                                        )
                                    })}
                                </AnimatePresence>
                            )}
                        </motion.div>

                        {/* Pagination Controls */}
                        {filteredProducts.length > itemsPerPage && (
                            <div className="mt-16 flex justify-center">
                                <nav className="relative z-0 inline-flex rounded-full shadow-sm bg-white dark:bg-slate-800 p-1 border border-gray-200 dark:border-slate-700" aria-label="Pagination">
                                    <button
                                        disabled={currentPage === 1}
                                        onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                                        className="relative inline-flex items-center px-4 py-2 rounded-full text-sm font-bold text-gray-500 hover:bg-gray-50 dark:hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                    >
                                        Prev
                                    </button>
                                    <div className="hidden sm:flex items-center px-2 space-x-1 border-x border-gray-200 dark:border-slate-700 mx-2">
                                        {[...Array(Math.ceil(filteredProducts.length / itemsPerPage))].map((_, i) => (
                                            <button
                                                key={i + 1}
                                                onClick={() => setCurrentPage(i + 1)}
                                                className={`w-10 h-10 rounded-full text-sm font-bold transition-colors ${currentPage === i + 1 ? 'bg-primary-600 text-white shadow-md' : 'bg-transparent text-gray-700 dark:text-slate-300 hover:bg-gray-100 dark:hover:bg-slate-700'}`}
                                            >
                                                {i + 1}
                                            </button>
                                        ))}
                                    </div>
                                    <button
                                        disabled={currentPage === Math.ceil(filteredProducts.length / itemsPerPage)}
                                        onClick={() => setCurrentPage(p => Math.min(Math.ceil(filteredProducts.length / itemsPerPage), p + 1))}
                                        className="relative inline-flex items-center px-4 py-2 rounded-full text-sm font-bold text-gray-900 dark:text-white hover:bg-gray-50 dark:hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                    >
                                        Next
                                    </button>
                                </nav>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Products;

import { useState, useRef } from 'react';
import { Package, CheckCircle, Truck as TruckIcon, Home } from 'lucide-react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useCurrency } from '../context/CurrencyContext';

// --- 3D Components ---

const AnimatedTruck = ({ progress }) => {
    const truckRef = useRef();

    useFrame((state, delta) => {
        if (!truckRef.current) return;
        // Target X position based on progress (-4 to +4)
        const targetX = -4 + (progress * 8);
        // Smoothly interpolate position
        truckRef.current.position.x = THREE.MathUtils.lerp(truckRef.current.position.x, targetX, 0.05);
    });

    return (
        <group ref={truckRef} position={[-4, 0.5, 0]}>
            <Float floatIntensity={0.2} speed={5}>
                <ProceduralTruck scale={0.7} />
            </Float>
        </group>
    );
};

const Scenery = () => {
    return (
        <group>
            {/* Road */}
            <mesh position={[0, 0, 0]} receiveShadow rotation={[-Math.PI / 2, 0, 0]}>
                <planeGeometry args={[12, 3]} />
                <meshStandardMaterial color="#334155" roughness={0.8} />
            </mesh>

            {/* Road lines */}
            {[-3, -1, 1, 3].map((x) => (
                <mesh key={x} position={[x, 0.01, 0]} rotation={[-Math.PI / 2, 0, 0]}>
                    <planeGeometry args={[1, 0.1]} />
                    <meshBasicMaterial color="#e2e8f0" />
                </mesh>
            ))}

            {/* Grass */}
            <mesh position={[0, -0.05, -2.5]} receiveShadow rotation={[-Math.PI / 2, 0, 0]}>
                <planeGeometry args={[12, 2]} />
                <meshStandardMaterial color="#16a34a" roughness={1} />
            </mesh>

            <mesh position={[0, -0.05, 2.5]} receiveShadow rotation={[-Math.PI / 2, 0, 0]}>
                <planeGeometry args={[12, 2]} />
                <meshStandardMaterial color="#16a34a" roughness={1} />
            </mesh>

            {/* Trees */}
            {[[-4, -2], [-2, -2.5], [1, -1.8], [3, -2.2], [-3, 2], [0, 2.5], [4, 1.8]].map((pos, i) => (
                <group key={i} position={[pos[0], 0, pos[1]]}>
                    <mesh position={[0, 0.4, 0]} castShadow>
                        <cylinderGeometry args={[0.1, 0.1, 0.8]} />
                        <meshStandardMaterial color="#78350f" />
                    </mesh>
                    <mesh position={[0, 1.2, 0]} castShadow>
                        <coneGeometry args={[0.6, 1.5, 8]} />
                        <meshStandardMaterial color="#15803d" />
                    </mesh>
                </group>
            ))}

            {/* Destination House */}
            <group position={[4.5, 0.5, -1.5]} rotation={[0, -Math.PI / 6, 0]}>
                <mesh castShadow position={[0, 0, 0]}>
                    <boxGeometry args={[1.5, 1, 1.5]} />
                    <meshStandardMaterial color="#f8fafc" />
                </mesh>
                <mesh castShadow position={[0, 0.8, 0]} rotation={[0, Math.PI / 4, 0]}>
                    <coneGeometry args={[1.4, 1, 4]} />
                    <meshStandardMaterial color="#ef4444" />
                </mesh>
            </group>
        </group>
    );
};

const TrackOrder = () => {
    const { formatPrice } = useCurrency();
    const [orderId, setOrderId] = useState('VTX-99812');
    const [isTracking, setIsTracking] = useState(false);
    const [orderStatus, setOrderStatus] = useState(null);

    const handleTrack = (e) => {
        e.preventDefault();
        if (!orderId.trim()) return;

        setIsTracking(true);
        // Simulate API Call
        setTimeout(() => {
            setOrderStatus({
                id: orderId,
                date: 'Oct 24, 2026',
                estimatedDelivery: 'Oct 28, 2026',
                status: 'in_transit', // processing, shipped, in_transit, delivered
                items: [
                    { name: 'Vertexia Pro Wireless Headphones', price: 299.00, image: 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=800&q=80' }
                ]
            });
            setIsTracking(false);
        }, 1500);
    };

    const steps = [
        { id: 'processing', label: 'Order Processed', icon: Package, date: 'Oct 24, 10:00 AM' },
        { id: 'shipped', label: 'Order Shipped', icon: CheckCircle, date: 'Oct 25, 02:30 PM' },
        { id: 'in_transit', label: 'In Transit', icon: TruckIcon, date: 'Oct 26, 08:15 AM' },
        { id: 'delivered', label: 'Delivered', icon: Home, date: 'Pending' }
    ];

    const currentStepIndex = orderStatus ? steps.findIndex(s => s.id === orderStatus.status) : -1;
    // Map index (0 to 3) to progress (0 to 1) for truck animation
    const progress = currentStepIndex >= 0 ? currentStepIndex / 3 : 0;

    return (
        <div className="min-h-screen bg-[#F8FAFC] dark:bg-[#020617] pt-24 pb-16 transition-colors duration-300 relative overflow-hidden">
            <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-primary-400/20 rounded-full blur-[120px] pointer-events-none" />

            <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
                <div className="text-center mb-12">
                    <h1 className="text-4xl md:text-5xl font-black text-slate-900 dark:text-white mb-4 tracking-tight">Track Your Order</h1>
                    <p className="text-lg text-slate-600 dark:text-slate-400 font-medium">Enter your Vertexia Order ID to see real-time shipping updates.</p>
                </div>

                {/* Tracking Input */}
                <Tilt tiltMaxAngleX={5} tiltMaxAngleY={5} scale={1.01} transitionSpeed={2000} className="w-full max-w-2xl mx-auto mb-16">
                    <form onSubmit={handleTrack} className="bg-white/80 dark:bg-slate-800/80 backdrop-blur-xl p-4 rounded-3xl shadow-xl border border-white/50 dark:border-slate-700/50 flex flex-col sm:flex-row gap-4 relative overflow-hidden group">
                        <div className="absolute inset-0 bg-gradient-to-r from-primary-500/10 to-indigo-500/10 opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none" />

                        <div className="relative flex-1">
                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                <Package className="h-6 w-6 text-slate-400" />
                            </div>
                            <input
                                type="text"
                                value={orderId}
                                onChange={(e) => setOrderId(e.target.value)}
                                placeholder="Enter Order ID (e.g. VTX-99812)"
                                className="block w-full pl-12 pr-4 py-4 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-slate-900 dark:text-white font-bold placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all"
                                required
                            />
                        </div>
                        <button
                            type="submit"
                            disabled={isTracking}
                            className="bg-primary-600 hover:bg-primary-500 text-white px-8 py-4 rounded-2xl font-black shadow-lg transition-all flex items-center justify-center disabled:opacity-70"
                        >
                            {isTracking ? (
                                <Clock className="animate-spin h-6 w-6" />
                            ) : (
                                <>
                                    <Search className="h-5 w-5 mr-2" /> Track
                                </>
                            )}
                        </button>
                    </form>
                </Tilt>

                {/* Tracking Results */}
                {orderStatus && (
                    <motion.div
                        initial={{ opacity: 0, y: 40 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }}
                        className="bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-700 overflow-hidden"
                    >
                        {/* 3D Diorama Header */}
                        <div className="h-64 sm:h-80 w-full bg-sky-200 dark:bg-slate-900 relative cursor-grab active:cursor-grabbing border-b border-slate-100 dark:border-slate-700">
                            <Canvas shadows camera={{ position: [0, 6, 8], fov: 45 }}>
                                <Environment preset="city" />
                                <ambientLight intensity={0.4} />
                                <directionalLight position={[10, 10, 5]} intensity={1.5} castShadow shadow-mapSize-width={1024} shadow-mapSize-height={1024} />
                                <PresentationControls speed={1.5} global zoom={1} polar={[-0.1, Math.PI / 4]} azimuth={[-Math.PI / 4, Math.PI / 4]}>
                                    <Scenery />
                                    <AnimatedTruck progress={progress} />
                                </PresentationControls>
                                <ContactShadows position={[0, -0.1, 0]} opacity={0.4} scale={20} blur={2} far={4} />
                            </Canvas>
                            <div className="absolute top-4 left-4 bg-white/80 dark:bg-slate-800/80 backdrop-blur-md px-4 py-2 rounded-xl border border-slate-200/50 dark:border-slate-700/50 shadow-sm flex items-center">
                                <span className="w-2 h-2 bg-green-500 rounded-full mr-2 animate-pulse" />
                                <p className="text-xs font-black text-slate-800 dark:text-slate-200 uppercase tracking-widest text-[10px] sm:text-xs">Live GPS Tracking</p>
                            </div>
                        </div>

                        {/* Order Header Summary */}
                        <div className="bg-slate-50 dark:bg-slate-800/80 p-6 sm:p-8 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 relative z-10">
                            <div>
                                <p className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-1">Order #{orderStatus.id}</p>
                                <h3 className="text-2xl font-black text-slate-900 dark:text-white">Arriving by {orderStatus.estimatedDelivery}</h3>
                            </div>
                            <div className="px-4 py-2 bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400 rounded-xl font-bold border border-blue-200 dark:border-blue-800/50 shadow-sm">
                                Status: {steps[currentStepIndex]?.label || 'Unknown'}
                            </div>
                        </div>

                        {/* Timeline */}
                        <div className="p-6 sm:p-12 bg-white dark:bg-slate-800">
                            <div className="relative">
                                {/* Connecting Line */}
                                <div className="absolute left-[27px] top-4 bottom-4 w-1 bg-slate-100 dark:bg-slate-700 rounded-full" />
                                <div
                                    className="absolute left-[27px] top-4 w-1 bg-primary-500 rounded-full transition-all duration-1000 ease-out"
                                    style={{ height: `${(currentStepIndex / 3) * 100}%` }}
                                />

                                <div className="space-y-12">
                                    {steps.map((step, index) => {
                                        const isCompleted = index <= currentStepIndex;
                                        const isCurrent = index === currentStepIndex;

                                        return (
                                            <div key={step.id} className="relative flex items-start group">
                                                {/* Icon */}
                                                <div className={`relative z-10 w-14 h-14 rounded-2xl flex items-center justify-center flex-shrink-0 border-4 border-white dark:border-slate-800 transition-colors duration-500 shadow-sm ${isCompleted ? 'bg-primary-500 text-white shadow-primary-500/30' : 'bg-slate-100 dark:bg-slate-700 text-slate-400'}`}>
                                                    <step.icon size={24} className={isCurrent ? 'animate-bounce' : ''} />
                                                </div>

                                                {/* Content */}
                                                <div className="ml-6 pt-2 flex-1">
                                                    <h4 className={`text-lg font-bold ${isCompleted ? 'text-slate-900 dark:text-white' : 'text-slate-500 dark:text-slate-500'}`}>
                                                        {step.label}
                                                    </h4>
                                                    <p className={`text-sm mt-1 font-medium ${isCompleted ? 'text-slate-500 dark:text-slate-400' : 'text-slate-400 dark:text-slate-600'}`}>
                                                        {step.date}
                                                    </p>
                                                </div>

                                                {isCurrent && (
                                                    <motion.div
                                                        initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }}
                                                        className="hidden sm:flex items-center text-xs font-bold text-primary-600 dark:text-primary-400 italic bg-primary-50 dark:bg-primary-900/20 px-3 py-1.5 rounded-lg border border-primary-100 dark:border-primary-800/50 mt-2"
                                                    >
                                                        Current Status
                                                    </motion.div>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>

                        {/* Order Items */}
                        <div className="p-6 sm:p-10 bg-slate-50 dark:bg-slate-900/30 border-t border-slate-100 dark:border-slate-700">
                            <h4 className="font-black text-slate-900 dark:text-white mb-6 uppercase tracking-wider text-sm flex items-center"><Package className="mr-2" size={18} /> Shipment Details</h4>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                {orderStatus.items.map((item, idx) => (
                                    <div key={idx} className="flex flex-col sm:flex-row items-center gap-4 bg-white dark:bg-slate-800 p-4 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700 hover:shadow-md transition-all group">
                                        <div className="w-full sm:w-24 h-24 bg-slate-50 dark:bg-slate-900/50 rounded-2xl overflow-hidden group-hover:scale-105 transition-transform">
                                            <img src={item.image} alt={item.name} className="w-full h-full object-cover mix-blend-multiply dark:mix-blend-normal" />
                                        </div>
                                        <div className="flex-1 text-center sm:text-left">
                                            <h5 className="font-bold text-slate-900 dark:text-white text-sm sm:text-base leading-tight">{item.name}</h5>
                                            <p className="font-black text-primary-600 dark:text-primary-400 mt-2 text-lg">{formatPrice(item.price)}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </motion.div>
                )}
            </div>
        </div>
    );
};

export default TrackOrder;
